package main
import ("encoding/csv"; "fmt"; "math"; "os"; "path/filepath")
type Scenario struct { Name string; EiD, Mu, MuG, DC, MC float64 }
func run(s Scenario) []string { output:=100.0; ei:=0.42; mu:=s.Mu; ap:=1.0; temp:=1.2; ce:=0.0; cd:=0.0; cc:=0.0; w:=0.0; avg:=0.0; n:=0.0; fe:=0.0; for y:=2025; y<=2100; y+=5 { if y>2025 { output*=math.Pow(1.012,5); ei=math.Max(0.02,ei*math.Pow(1-s.EiD,5)); mu=math.Min(0.98,mu+s.MuG) }; e:=output*ei*(1-mu); if y>2025 { ap=math.Max(0,ap+0.012*e-0.010*ap); temp=math.Max(0,temp+0.030*ap-0.012*temp) }; d:=s.DC*temp*temp*output; c:=s.MC*mu*mu*output; cons:=math.Max(0,output-d-c); ww:=math.Log(cons+1)/math.Pow(1.015,float64(y-2025)); ce+=e; cd+=d; cc+=c; w+=ww; avg+=mu; n++; fe=e }; label:="lower climate pressure pathway"; if temp>3 { label="high climate pressure pathway" }; return []string{s.Name,fmt.Sprintf("%.6f",fe),fmt.Sprintf("%.6f",temp),fmt.Sprintf("%.6f",ce),fmt.Sprintf("%.6f",cd),fmt.Sprintf("%.6f",cc),fmt.Sprintf("%.6f",w),fmt.Sprintf("%.6f",avg/n),label} }
func main(){ os.MkdirAll("outputs/tables",0755); p:=filepath.Join("outputs","tables","go_iam_pathway_summary.csv"); f,_:=os.Create(p); defer f.Close(); wr:=csv.NewWriter(f); defer wr.Flush(); wr.Write([]string{"scenario","final_emissions","final_temperature_proxy","cumulative_emissions","cumulative_damages","cumulative_mitigation_cost","discounted_welfare_proxy","average_mitigation_rate","diagnostic_label"}); for _,s:=range []Scenario{{"delayed_transition",0.006,0.02,0.010,0.012,0.040},{"moderate_transition",0.012,0.06,0.025,0.010,0.040},{"accelerated_decarbonization",0.018,0.10,0.045,0.008,0.055},{"high_innovation_pathway",0.026,0.08,0.040,0.008,0.038}}{ wr.Write(run(s)) }; fmt.Println("Go IAM diagnostics complete."); fmt.Println(p) }
